import { bar_position, bar_styles } from '../bar/bar-encode';
import { bullet_levelmarker_position, bullet_levelmarker_styles } from '../bullet/bullet-levelmarker-encode.js';
import { gantt_connector_position, gantt_connector_styles } from './gantt-connector-encode.js';
import { gantt_marker_position, gantt_marker_styles } from './gantt-marker-encode.js';

export function gantt_encode_collectors() {
    bar_position.call(this);
    bullet_levelmarker_position.call(this);
    gantt_marker_position.call(this);
    gantt_connector_position.call(this);

    bar_styles.call(this);
    bullet_levelmarker_styles.call(this);
    gantt_marker_styles.call(this);
    gantt_connector_styles.call(this);
}
